/* ═══════════ Dropy Wishlist ═══════════ */

/* heart button (cards + PDP) */
.dw-heart {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 38px;
  height: 38px;
  padding: 0;
  border: 0;
  border-radius: 50%;
  cursor: pointer;
  color: #4b5563;
  background: rgba(255, 255, 255, 0.55);
  border: 1px solid rgba(255, 255, 255, 0.7);
  box-shadow: 0 2px 8px rgba(31, 38, 135, 0.12), inset 0 1px 1px rgba(255, 255, 255, 0.6);
  transition: transform 0.15s ease, color 0.15s ease, background 0.15s ease;
  z-index: 5;
}
.dw-heart:hover { transform: scale(1.12); background: rgba(255, 255, 255, 0.8); }
.dw-heart:active { transform: scale(0.95); }
.dw-heart.dw-on { color: #ef4444; }
.dw-heart.dw-loading { opacity: 0.5; pointer-events: none; }
.dw-heart svg { display: block; }

/* heart on a product card — float top-right of the image */
.dw-heart--card {
  position: absolute;
  top: 10px;
  right: 10px;
  width: 34px;
  height: 34px;
}

/* PDP heart row */
.dw-pdp-row {
  display: flex;
  align-items: center;
  gap: 10px;
  margin: 14px 0 4px;
}
.dw-heart--pdp {
  width: 44px;
  height: 44px;
  background: #fff;
  border: 1px solid #e5e7eb;
}
.dw-pdp-label {
  font-size: 14px;
  font-weight: 600;
  color: #374151;
  cursor: pointer;
  -webkit-user-select: none;
  user-select: none;
}

/* mini toast on the heart */
.dw-flash {
  position: absolute;
  bottom: calc(100% + 6px);
  left: 50%;
  transform: translateX(-50%) translateY(4px);
  background: #111827;
  color: #fff;
  font-size: 11px;
  font-weight: 600;
  white-space: nowrap;
  padding: 4px 9px;
  border-radius: 6px;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.2s ease, transform 0.2s ease;
  z-index: 10;
}
.dw-flash.dw-flash-show { opacity: 1; transform: translateX(-50%) translateY(0); }

/* header icon + badge */
.dw-header-icon {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  color: inherit;
  width: 40px;
  height: 40px;
  text-decoration: none;
}
.dw-header-icon svg { display: block; }
.dw-badge {
  position: absolute;
  top: 2px;
  right: 2px;
  min-width: 17px;
  height: 17px;
  padding: 0 4px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #ef4444;
  color: #fff;
  font-size: 10px;
  font-weight: 700;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  line-height: 1;
  border-radius: 99px;
}

/* ───── wishlist page ───── */
#dropy-wishlist-root {
  font-family: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}
.dw-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
  gap: 18px;
}
@media (max-width: 600px) {
  .dw-grid { grid-template-columns: repeat(2, 1fr); gap: 12px; }
}
.dw-card {
  position: relative;
  display: flex;
  flex-direction: column;
  border: 1px solid #eee;
  border-radius: 14px;
  overflow: hidden;
  background: #fff;
  transition: box-shadow 0.2s ease, transform 0.2s ease;
}
.dw-card:hover { box-shadow: 0 8px 24px -8px rgba(0, 0, 0, 0.15); transform: translateY(-2px); }
.dw-card-remove {
  position: absolute;
  top: 8px;
  right: 8px;
  width: 28px;
  height: 28px;
  border: 0;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.95);
  color: #6b7280;
  font-size: 18px;
  line-height: 1;
  cursor: pointer;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.12);
  z-index: 3;
  transition: color 0.15s, transform 0.15s;
}
.dw-card-remove:hover { color: #ef4444; transform: scale(1.1); }
.dw-card-img {
  display: block;
  aspect-ratio: 1 / 1;
  background: #f7f7f7;
  overflow: hidden;
}
.dw-card-img img { width: 100%; height: 100%; object-fit: cover; }
.dw-card-noimg { width: 100%; height: 100%; background: #f0f0f0; }
.dw-card-title {
  display: -webkit-box;
  -webkit-line-clamp: 2;
  line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  font-size: 13px;
  font-weight: 500;
  line-height: 1.4;
  color: #1f2937;
  text-decoration: none;
  padding: 12px 12px 4px;
}
.dw-card-title:hover { color: #ea580c; }
.dw-card-price {
  padding: 0 12px;
  font-size: 14px;
  font-weight: 700;
  color: #111827;
}
.dw-card-cmp {
  font-weight: 500;
  font-size: 12px;
  color: #9ca3af;
  text-decoration: line-through;
  margin-left: 4px;
}
.dw-card-atc {
  margin: 10px 12px 12px;
  padding: 9px;
  border: 0;
  border-radius: 999px;
  background: linear-gradient(135deg, #fb923c, #ea580c);
  color: #fff;
  font-family: inherit;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.15s, box-shadow 0.15s;
}
.dw-card-atc:hover { transform: translateY(-1px); box-shadow: 0 6px 16px -6px rgba(234, 88, 12, 0.5); }
.dw-card-atc.dw-soldout { background: #e5e7eb; color: #9ca3af; cursor: not-allowed; }

/* empty state */
.dw-empty {
  text-align: center;
  padding: 60px 20px;
  color: #6b7280;
}
.dw-empty-heart { color: #d1d5db; display: flex; justify-content: center; margin-bottom: 8px; }
.dw-empty-heart svg { width: 48px; height: 48px; }
.dw-empty h3 { font-size: 18px; font-weight: 700; color: #374151; margin: 0 0 6px; }
.dw-empty p { font-size: 14px; margin: 0 0 18px; }
.dw-empty-cta {
  display: inline-block;
  padding: 11px 26px;
  background: linear-gradient(135deg, #fb923c, #ea580c);
  color: #fff;
  font-weight: 600;
  font-size: 14px;
  text-decoration: none;
  border-radius: 999px;
}

/* ── Maximize theme: card heart top-right (badge is top-left) ── */
.product-card__image-wrapper .dw-heart--card {
  top: 8px;
  right: 8px;
}
/* mobile nav wishlist item — heart icon + badge */
.dw-mnav-icon { position: relative; display: inline-flex; }
.dw-mnav-icon svg { width: 24px; height: 24px; }
.dw-mnav-icon .dw-heart, .dw-mobile-nav-item .dw-heart { all: unset; }
.dw-badge--mnav {
  position: absolute;
  top: -6px;
  right: -8px;
  min-width: 15px;
  height: 15px;
  font-size: 9px;
}
.dw-mobile-nav-item .dw-mnav-icon svg path { fill: #ef4444; }
.dw-mobile-nav-item { text-decoration: none; color: inherit; }

/* ── Mobile nav: make room for 5th item (reduce side padding) ── */
#bottom-mobile-nav .flex.px-9 { padding-left: 1rem; padding-right: 1rem; }
.dw-mobile-nav-item { min-width: 56px !important; text-decoration: none; color: inherit; }
.dw-mnav-icon { position: relative; display: inline-flex; align-items: center; justify-content: center; }
.dw-mnav-icon svg { width: 24px; height: 24px; display: block; }
.dw-badge--mnav {
  position: absolute;
  top: -5px;
  right: -7px;
  min-width: 15px;
  height: 15px;
  padding: 0 3px;
  font-size: 9px;
}
/* ── Desktop header heart: size + color to match neighbours ── */
.dw-header-icon {
  width: auto;
  height: auto;
  padding: 0 6px;
  color: rgba(var(--color-heading, 48 48 48), 1);
}
.dw-header-icon svg { width: 24px; height: 24px; }
.dw-header-icon .dw-badge { top: -4px; right: 0; }

/* ── Header heart: filled red + gentle heartbeat ── */
.dw-header-icon .dw-hdr-heart,
.dw-mobile-nav-item .dw-hdr-heart {
  display: block;
  transform-origin: center;
  animation: dw-heartbeat 2.2s ease-in-out infinite;
}
@keyframes dw-heartbeat {
  0%, 100% { transform: scale(1); }
  10% { transform: scale(1.18); }
  20% { transform: scale(1); }
  30% { transform: scale(1.12); }
  40% { transform: scale(1); }
}
.dw-header-icon:hover .dw-hdr-heart { animation-duration: 0.9s; }
@media (prefers-reduced-motion: reduce) {
  .dw-header-icon .dw-hdr-heart,
  .dw-mobile-nav-item .dw-hdr-heart { animation: none; }
}

/* ── Hide desktop header heart on mobile (mobile uses the nav-bar item) ── */
@media (max-width: 767px) {
  .dw-header-icon { display: none !important; }
}
